    private class Entry(val w: String, val fn: Double, val jamo: List<String>)
    private val koByLen = HashMap<Int, ArrayList<Entry>>()
    private val koSet = HashSet<String>()
    private val enByLen = HashMap<Int, ArrayList<Entry>>()
    private val enSet = HashSet<String>()
    @Volatile private var loaded = false

    private val sameGroup = HashSet<String>()
    private val nearVowel = HashSet<String>()
    private val qadj = HashSet<String>()

    private fun buildCostSets() {
        for (g in listOf("ㄱㅋㄲ","ㄷㅌㄸ","ㅂㅍㅃ","ㅅㅎㅆ","ㅈㅊㅉ","ㄴㄹ","ㅇㅁ"))
            for (a in g) for (b in g) if (a != b) sameGroup.add("" + a + b)
        for (p in listOf("ㅏㅓ","ㅗㅜ","ㅏㅑ","ㅓㅕ","ㅗㅛ","ㅜㅠ","ㅐㅔ","ㅚㅟ","ㅡㅜ","ㅡㅗ","ㅐㅏ","ㅔㅓ","ㅕㅛ","ㅑㅕ")) {
            nearVowel.add("" + p[0] + p[1]); nearVowel.add("" + p[1] + p[0])
        }
        val rows = listOf("qwertyuiop","asdfghjkl","zxcvbnm")
        val pos = HashMap<Char, Pair<Int,Int>>()
        rows.forEachIndexed { ri, r -> r.forEachIndexed { ci, ch -> pos[ch] = ri to ci } }
        val keys = pos.keys.toList()
        for (a in keys) for (b in keys) if (a != b) {
            val pa = pos[a]!!; val pb = pos[b]!!
            if (abs(pa.first - pb.first) <= 1 && abs(pa.second - pb.second) <= 1) qadj.add("" + a + b)
        }
    }

    private fun decompose(s: String): List<String> {
        val out = ArrayList<String>()
        for (ch in s) {
            val c = ch.code
            if (c in 0xAC00..0xD7A3) {
                val idx = c - 0xAC00
                out.add(Han.CHO[idx / 588]); out.add(Han.JUNG[(idx % 588) / 28])
                val ki = idx % 28
                if (ki > 0) { val jg = Han.JONG[ki]; val sp = Han.JONG_SPLIT[jg]; if (sp != null) out.addAll(sp) else out.add(jg) }
            } else if (ch != ' ') out.add(ch.toString())
        }
        return out
    }

    @Synchronized fun ensureLoaded() {
        if (loaded) return
        buildCostSets()
        val ko = KO_WORDS.split(" ")
        for ((i, w) in ko.withIndex()) {
            if (w.isEmpty()) continue
            val e = Entry(w, 1.0 - i.toDouble() / ko.size, decompose(w))
            koByLen.getOrPut(e.jamo.size) { ArrayList() }.add(e); koSet.add(w)
        }
        val en = EN_WORDS.split(" ")
        for ((i, w) in en.withIndex()) {
            if (w.isEmpty()) continue
            val e = Entry(w, 1.0 - i.toDouble() / en.size, w.map { it.toString() })
            enByLen.getOrPut(e.jamo.size) { ArrayList() }.add(e); enSet.add(w)
        }
        loaded = true
    }

    private fun subCostKo(a: String, b: String): Double {
        if (a == b) return 0.0
        if (sameGroup.contains(a + b)) return 0.4
        if (nearVowel.contains(a + b)) return 0.5
        return 1.0
    }
    private fun subCostEn(a: String, b: String): Double {
        if (a == b) return 0.0
        if (qadj.contains(a + b)) return 0.5
        return 1.0
    }

    private fun wdist(a: List<String>, b: List<String>, thr: Double, ko: Boolean, tcost: Double): Double {
        val n = a.size; val m = b.size
        if (abs(n - m) > thr + 0.5) return 99.0
        var prev = DoubleArray(m + 1) { it.toDouble() }
        var prev2 = DoubleArray(m + 1)
        for (i in 1..n) {
            val cur = DoubleArray(m + 1); cur[0] = i.toDouble(); var rowMin = cur[0]
            for (j in 1..m) {
                val sc = if (ko) subCostKo(a[i - 1], b[j - 1]) else subCostEn(a[i - 1], b[j - 1])
                var v = minOf(prev[j] + 1, cur[j - 1] + 1, prev[j - 1] + sc)
                if (i > 1 && j > 1 && a[i - 1] == b[j - 2] && a[i - 2] == b[j - 1]) v = minOf(v, prev2[j - 2] + tcost)
                cur[j] = v; if (v < rowMin) rowMin = v
            }
            if (rowMin > thr) return 99.0
            prev2 = prev; prev = cur
        }
        return prev[m]
    }

    private class Cand(val w: String, val d: Double, val fn: Double)

    private fun lookup(word: String, ko: Boolean): List<Cand> {
        ensureLoaded()
        val key = if (ko) word else word.lowercase()
        val jam = if (ko) decompose(word) else key.map { it.toString() }
        val L = jam.size
        if (L == 0) return emptyList()
        val byLen = if (ko) koByLen else enByLen
        val thr = 2.0
        val tcost = if (ko) 0.6 else 0.4
        val res = ArrayList<Cand>()
        for (len in maxOf(1, L - 2)..(L + 2)) {
            val bucket = byLen[len] ?: continue
            for (e in bucket) {
                if (e.w == key) { res.add(Cand(e.w, 0.0, e.fn)); continue }
                val d = wdist(jam, e.jamo, thr, ko, tcost)
                if (d <= thr) res.add(Cand(e.w, d, e.fn))
            }
        }
        res.sortBy { it.d - 0.45 * it.fn }
        val seen = HashSet<String>(); val out = ArrayList<Cand>()
        for (r in res) if (seen.add(r.w)) { out.add(r); if (out.size >= 5) break }
        return out
    }

    private fun matchCase(src: String, dst: String): String {
        if (src.isNotEmpty() && src[0].isUpperCase()) return dst.replaceFirstChar { it.uppercase() }
        return dst
    }

    fun suggest(word: String, mode: String): List<String> {
        if (mode == "sym") return emptyList()
        val ko = mode != "en"
        val w = word.trim()
        if (w.isEmpty()) return emptyList()
        if (!ko && !w.all { it.code < 128 && it.isLetter() }) return emptyList()
        val key = if (ko) w else w.lowercase()
        val cands = lookup(w, ko)
        val out = ArrayList<String>()
        cands.firstOrNull { it.w == key }?.let { out.add(if (ko) it.w else matchCase(w, it.w)) }
        for (c in cands) {
            if (c.w == key) continue
            val disp = if (ko) c.w else matchCase(w, c.w)
            if (!out.contains(disp)) out.add(disp)
            if (out.size >= 4) break
        }
        return out
    }

    fun autoCorrect(word: String, mode: String): String? {
        if (mode == "sym") return null
        val ko = mode != "en"
        if (ko) {
            if (koSet.contains(word)) return null
            val best = lookup(word, true).firstOrNull { it.w != word } ?: return null
            if (best.d <= 1.0 && best.fn >= 0.30) return best.w
            return null
        } else {
            val lw = word.lowercase()
            if (lw.length < 3 || !lw.all { it in 'a'..'z' }) return null
            if (enSet.contains(lw)) return null
            val best = lookup(lw, false).firstOrNull { it.w != lw } ?: return null
            if (best.d <= 1.0 && best.fn >= 0.40) return matchCase(word, best.w)
            return null
        }
    }
}
